function SourceBadge({ count }) {
  const styles = {
    3: "bg-amber-500 text-slate-900",
    2: "bg-slate-600 text-slate-200",
    1: "bg-slate-800 text-slate-500",
  };
  return (
    <span className={`inline-flex items-center justify-center w-5 h-5 rounded-full text-xs font-bold flex-shrink-0 ${styles[count]}`}>
      {count}
    </span>
  );
}

function ScenarioPill({ id }) {
  const s = SCENARIOS.find(sc => sc.id === id);
  if (!s) return null;
  return (
    <span className={`inline-flex items-center gap-1.5 px-2 py-0.5 rounded text-xs font-medium ${SC[id].pill}`}>
      <span className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${SC[id].dot}`} />
      {id} · {s.name}
    </span>
  );
}

function TierBadge({ tier }) {
  const styles = {
    1: "bg-amber-950 text-amber-300 border border-amber-800",
    2: "bg-slate-800 text-slate-400 border border-slate-700",
    3: "bg-slate-900 text-slate-600 border border-slate-800",
  };
  return (
    <span className={`text-xs px-1.5 py-0.5 rounded font-medium ${styles[tier]}`}>
      Tier {tier}
    </span>
  );
}

function DotCell({ count, scId }) {
  if (count === 0) return <div className="flex justify-center text-slate-800">—</div>;
  return (
    <div className="flex gap-1 justify-center items-center">
      {[...Array(count)].map((_, i) => (
        <div key={i} className={`w-2 h-2 rounded-full ${SC[scId].dot}`} />
      ))}
    </div>
  );
}

